// Parse each Drive trigger payload — extract { file_id, lesson_id, filename, mime_type }.
// Iterates over ALL input items so multi-file drops produce one output item per file.
// lesson_id is derived from filename (e.g., 'sleep_002.mp3' → 'sleep_002').
const out = [];
for (const i of $input.all()) {
  const item = i.json || {};
  const filename = item.name || '';
  const file_id = item.id;
  const mime_type = item.mimeType || '';

  if (!file_id || !filename) {
    console.warn('Drive trigger payload missing id/name — skipping:', JSON.stringify(item));
    continue;
  }

  // Strip extension and sanitize for use as a sheet/file key.
  const baseName = filename.replace(/\.[^./\\]+$/, '');
  const lesson_id = baseName.trim().toLowerCase().replace(/[^a-z0-9_-]+/g, '_').replace(/^_+|_+$/g, '');
  if (!lesson_id) {
    console.warn('Could not derive lesson_id from filename — skipping:', filename);
    continue;
  }

  // Sanity: skip non-audio files (Drive trigger may fire on any file dropped in the folder).
  const looksAudio = /^audio\//.test(mime_type) || /\.(mp3|wav|m4a|aac|flac|ogg|opus)$/i.test(filename);
  if (!looksAudio) {
    console.warn('Skipping non-audio file:', filename, mime_type);
    continue;
  }

  out.push({ json: { file_id, lesson_id, filename, mime_type } });
}
return out;

// Collapse N Parse Filename items down to 1 sentinel item so the archive chain
// (List → Plan → Move) fires exactly once per Drive Trigger activation, not once
// per dropped file. Carries the set of just-dropped file IDs so Archive Previous Run
// can exclude them from the move list.
const newFileIds = $('Parse Filename').all().map(i => i.json.file_id).filter(Boolean);
const newFileNames = $('Parse Filename').all().map(i => i.json.filename).filter(Boolean);
return [{ json: { archive_run_at: new Date().toISOString(), new_file_ids: newFileIds, new_file_names: newFileNames } }];

// Plan Sources — emits one item per source folder that downstream List Files
// will hit via Drive REST. We dedupe folder IDs (in case fallback chains collapsed
// vtt → full → segments onto the same folder) so we don't list the same folder
// twice. drive_archive_folder_id is validated here, BEFORE any List/Move starts.
const cfg = {};
$('Read Config (Archive)').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const ARCHIVE_PARENT = cfg.drive_archive_folder_id;
if (!ARCHIVE_PARENT) {
  throw new Error('drive_archive_folder_id missing from config sheet — required for the archive feature. Either set it to the Drive folder ID of 05_archive, or remove the archive chain from W_Master.');
}
if (!cfg.drive_input_folder_id) throw new Error('drive_input_folder_id missing from config sheet');
if (!cfg.drive_output_folder_id) throw new Error('drive_output_folder_id missing from config sheet');

const sources = [
  { src_key: '01_input',    folder_id: cfg.drive_input_folder_id },
  { src_key: '02_output', folder_id: cfg.drive_output_folder_id },
  { src_key: '03_full',     folder_id: cfg.drive_output_full_folder_id || cfg.drive_output_folder_id },
  { src_key: '04_vtt',      folder_id: cfg.drive_output_vtt_folder_id || cfg.drive_output_full_folder_id || cfg.drive_output_folder_id },
];

const seen = new Set();
const out = [];
for (const s of sources) {
  if (!s.folder_id || seen.has(s.folder_id)) continue;
  seen.add(s.folder_id);
  out.push({ json: { src_key: s.src_key, folder_id: s.folder_id, q: `'${s.folder_id}' in parents and trashed = false` } });
}
return out;

// Plan Archive — aggregates the per-source-folder file lists, filters out the
// just-dropped trigger files, derives the archive subfolder name, and emits a
// single plan item that downstream nodes consume via $('Plan Archive').first().json.
// If nothing remains to archive (first run / pre-cleaned folders) → emits a single
// item with skip=true and Has Files? routes around the destructive chain.
const FOLDER_MIME = 'application/vnd.google-apps.folder';

const sources = $('Plan Sources').all().map(i => i.json);
const responses = $('List Files').all().map(i => i.json);

if (sources.length !== responses.length) {
  console.warn(`[Archive] source/response count mismatch: ${sources.length} vs ${responses.length}`);
}

const newFileIds = new Set(($('Once Per Run').first().json.new_file_ids || []));

const cfg = {};
$('Read Config (Archive)').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const toMove = [];
for (let i = 0; i < sources.length; i++) {
  const src = sources[i];
  const files = (responses[i] && responses[i].files) || [];
  for (const f of files) {
    if (f.mimeType === FOLDER_MIME) continue;       // never move subfolders
    if (newFileIds.has(f.id)) continue;             // skip just-dropped trigger files
    toMove.push({ id: f.id, name: f.name, src_key: src.src_key, src_folder: src.folder_id });
  }
}

if (toMove.length === 0) {
  console.log('[Archive] nothing to archive — folders already clean (first run or operator pre-cleaned)');
  return [{ json: { skip: true } }];
}

function basenameNoExt(name) { return (name || '').replace(/\.[^./\\]+$/, ''); }
let archiveBase = null;
const leftoverInputs = toMove.filter(f => f.src_key === '01_input').sort((a, b) => a.name.localeCompare(b.name));
if (leftoverInputs.length > 0) {
  archiveBase = basenameNoExt(leftoverInputs[0].name);
} else {
  const sample = toMove.find(f => /_(seg|full)_/.test(f.name));
  if (sample) archiveBase = sample.name.split(/_(seg|full)_/)[0];
}
if (!archiveBase) archiveBase = 'archive';

// Kyiv local time. 'sv-SE' locale → "YYYY-MM-DD HH:MM:SS"; turn into filename-safe
// "YYYY-MM-DD_HH-MM" (no seconds, underscore between date and time, hyphens not colons).
const kyivTime = new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Kyiv' });
const stamp = kyivTime.replace(' ', '_').replace(/:/g, '-').slice(0, 16);
const archive_name = `${archiveBase}_${stamp}`;

const SHEET_ID = cfg.sheets_document_id || '1LAxDWyV0pAxM1s5W00PTJ7OvFNQUxoeMSuszuOz3lDU';
const ARCHIVE_PARENT = cfg.drive_archive_folder_id;

console.log(`[Archive] plan: ${toMove.length} files → ${archive_name}/ (parent ${ARCHIVE_PARENT})`);

return [{ json: { skip: false, archive_name, archive_parent: ARCHIVE_PARENT, sheet_id: SHEET_ID, files: toMove } }];

// Plan Subfolders — emits one item per archive subfolder we need to create.
// Skips any src_key that has no files in the plan (e.g. if 04_vtt had 0 leftovers,
// we don't create an empty 04_vtt subfolder).
const plan = $('Plan Archive').first().json;
const rootId = $('Create Archive Root').first().json.id;
const presentKeys = new Set(plan.files.map(f => f.src_key));
const order = ['01_input', '02_output', '03_full', '04_vtt'];
return order
  .filter(k => presentKeys.has(k))
  .map(k => ({ json: { name: k, parent: rootId } }));

// Plan Moves — pairs each file in the plan with the just-created destination
// subfolder ID. Emits one item per file. Move File HTTP node fires per item.
const planSubInputs = $('Plan Subfolders').all().map(i => i.json);
const createdSubs = $('Create Subfolder').all().map(i => i.json);

// Pair by index: Create Subfolder fires once per Plan Subfolders item in order.
const subMap = {};
for (let i = 0; i < planSubInputs.length; i++) {
  if (!createdSubs[i] || !createdSubs[i].id) {
    console.error(`[Archive] missing subfolder response for ${planSubInputs[i].name}`);
    continue;
  }
  subMap[planSubInputs[i].name] = createdSubs[i].id;
}

const plan = $('Plan Archive').first().json;
const out = [];
for (const f of plan.files) {
  const dest = subMap[f.src_key];
  if (!dest) {
    console.error(`[Archive] no destination subfolder for ${f.name} (src_key=${f.src_key}) — skipping`);
    continue;
  }
  out.push({ json: { file_id: f.id, name: f.name, src_folder: f.src_folder, dest_folder: dest } });
}
console.log(`[Archive] planned ${out.length} moves`);
return out;

// Pass Lessons (after Archive) — re-emits the original Parse Filename items so
// Execute W1 fan-out works as before (one item per dropped file).
// Same idiom as the existing Pass Lessons (after W1/W2/W3) nodes.
return $('Parse Filename').all().map(i => ({ json: i.json }));

// Collapse downstream item stream back to one item per source lesson.
// Execute Workflow with mode=each emits aggregated sub-workflow output, which
// would multiply downstream item count and make the next Execute Workflow node
// call the sub-workflow far more times than intended. Re-emit Parse Filename items
// so the count is stable at N (= number of dropped files).
return $('Parse Filename').all().map(i => ({ json: i.json }));

// Build one Slack message per Parse Filename item (one per source audio file).
// Reads config from $('Read Config') and per-lesson needs_attention stats from $('Read Localizations').
// Emits { channel, text } — Slack Notify uses mrkdwn (clickable <url|label> links).
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const fullFolder = cfg.drive_output_full_folder_id || cfg.drive_output_folder_id;
const segmentsFolder = cfg.drive_output_folder_id;
const vttFolder  = cfg.drive_output_vtt_folder_id;
const regenUrl   = cfg.w_regen_workflow_url;
const channel    = cfg.slack_channel;
if (!channel) throw new Error('slack_channel missing from config sheet (set to channel ID like C01234ABCDE)');

const fullUrl     = fullFolder     ? `https://drive.google.com/drive/folders/${fullFolder}`     : null;
const segmentsUrl = segmentsFolder ? `https://drive.google.com/drive/folders/${segmentsFolder}` : null;
const vttUrl      = vttFolder      ? `https://drive.google.com/drive/folders/${vttFolder}`      : null;
const activeLangs = (cfg.active_langs || 'de,es,fr,it,pl,pt,tr').split(',').map(s => s.trim()).filter(Boolean);

const allLocs = $('Read Localizations').all().map(i => i.json || {});
const isFlagged = v => v === true || v === 'TRUE' || v === 'true';

function statsForLesson(lesson_id) {
  const rows = allLocs.filter(r => (r.segment_id || '').startsWith(lesson_id + '_'));
  const total = rows.length;
  const flagged = rows.filter(r => isFlagged(r.needs_attention)).length;
  const pct = total > 0 ? Math.round((flagged / total) * 100) : null;
  return { total, flagged, pct };
}

function buildMessage(p) {
  const lesson_id = p.json.lesson_id;
  const filename  = p.json.filename;
  const { total, flagged, pct } = statsForLesson(lesson_id);
  const naLine = pct === null ? 'n/a' : `${pct}% (${flagged} / ${total})`;

  const lines = [
    ':white_check_mark: *Dubbing complete*',
    '',
    `*Lesson:* ${lesson_id}`,
    `*Source file:* ${filename}`,
    `*Languages:* ${activeLangs.length} (${activeLangs.join(', ')})`,
    `*Needs attention:* ${naLine}`,
  ];
  if (fullUrl || segmentsUrl || vttUrl || regenUrl) lines.push('');
  if (fullUrl)     lines.push(`:file_folder: <${fullUrl}|Full audio (per-lang)>`);
  if (segmentsUrl) lines.push(`:musical_note: <${segmentsUrl}|Per-segment audio>`);
  if (vttUrl)      lines.push(`:closed_book: <${vttUrl}|VTT subtitles>`);
  if (regenUrl)    lines.push(`:wrench: <${regenUrl}|Regen Segments>`);

  return { json: { channel, text: lines.join('\n') } };
}

return $('Parse Filename').all().map(buildMessage);
